option.value:
/* Front office: compact navbar + logo size */
#navigation.site-navigation {
	padding: 10px 0;
}

#navigation .container .row {
	align-items: center;
}

/* Logo + company name */
.site-brand {
	gap: 0.65rem;
	min-width: 0;
}

.site-brand__name {
	font-family: "Lexend", system-ui, sans-serif;
	font-weight: 700;
	font-size: 1.35rem;
	line-height: 1.2;
	color: #0b104a;
	text-decoration: none;
	letter-spacing: -0.02em;
	white-space: nowrap;
}

.site-brand:hover .site-brand__name,
.site-brand:focus .site-brand__name,
.site-brand:focus-visible .site-brand__name {
	color: #2c7aff;
}

.site-brand:focus-visible {
	outline: 2px solid #2c7aff;
	outline-offset: 3px;
	border-radius: 4px;
}

.site-logo {
	display: inline-block;
	width: auto;
	max-width: 200px;
	line-height: 0;
	flex-shrink: 0;
	vertical-align: middle;
}

.site-logo img,
img.fo-brand-logo {
	display: block;
	max-height: 44px;
	width: auto;
	max-width: 100%;
	height: auto;
	object-fit: contain;
}

@media only screen and (max-width: 575px) {
	#navigation.site-navigation {
		padding: 12px 12px;
	}

	.site-logo img,
	img.fo-brand-logo {
		max-height: 38px;
	}

	.site-brand__name {
		font-size: 1.15rem;
	}
}

/* Navbar: back to home */
.fo-nav-back {
	display: inline-flex;
	align-items: center;
	justify-content: center;
	width: 2.25rem;
	height: 2.25rem;
	flex-shrink: 0;
	border-radius: 10px;
	color: #0b104a;
	background: #f0f4ff;
	border: 1px solid #dbe4ff;
	text-decoration: none;
	transition: background 0.2s, color 0.2s, border-color 0.2s;
}

.fo-nav-back:hover,
.fo-nav-back:focus {
	color: #2c7aff;
	background: #e8efff;
	border-color: #c7d7ff;
	text-decoration: none;
}

.fo-nav-back i {
	font-size: 1rem;
}

/* Login / register: clearer form */
.fo-login-section {
	background: linear-gradient(180deg, #f5f7fb 0%, #eef2f8 100%);
}

.fo-login-card {
	background: #fff;
	border-radius: 16px;
	padding: 2rem 1.75rem;
	box-shadow: 0 12px 40px rgba(15, 23, 42, 0.08);
	border: 1px solid rgba(15, 23, 42, 0.06);
}

.fo-login-card__title {
	font-family: "Lexend", system-ui, sans-serif;
	font-size: 1.5rem;
	font-weight: 700;
	color: #0b104a;
	margin: 0 0 0.5rem;
	line-height: 1.3;
}

.fo-login-card__lead {
	color: #5c6478;
	font-size: 0.95rem;
	margin: 0 0 1.5rem;
	line-height: 1.5;
}

.fo-login-alert {
	font-size: 0.9rem;
	border-radius: 10px;
}

.fo-field {
	margin-bottom: 1.15rem;
}

.fo-label {
	display: block;
	font-weight: 600;
	font-size: 0.875rem;
	color: #0b104a;
	margin-bottom: 0.4rem;
}

.fo-input.form-control {
	border-radius: 10px;
	border: 1px solid #d8dee8;
	padding: 0.65rem 0.85rem;
	font-size: 0.95rem;
	transition: border-color 0.2s, box-shadow 0.2s;
}

.fo-input.form-control:focus {
	border-color: #2c7aff;
	box-shadow: 0 0 0 3px rgba(44, 122, 255, 0.2);
	outline: none;
}

.fo-login-form .fo-login-actions {
	display: flex;
	flex-direction: column;
	gap: 0.75rem;
	margin-top: 0.25rem;
}

@media (min-width: 400px) {
	.fo-login-form .fo-login-actions:not(.fo-login-actions--stack) {
		flex-direction: row;
		align-items: stretch;
		gap: 0.75rem;
	}

	.fo-btn-primary {
		flex: 1 1 auto;
	}

	.fo-btn-secondary {
		flex: 0 0 auto;
		min-width: 7rem;
		justify-content: center;
		display: inline-flex;
		align-items: center;
	}
}

.fo-btn-primary.btn_one {
	width: 100%;
	border-radius: 10px;
	padding: 0.7rem 1rem;
	font-weight: 600;
}

.fo-btn-secondary.btn_two {
	border-radius: 10px;
	padding: 0.65rem 1.1rem;
	font-weight: 600;
	text-align: center;
}

.fo-login-actions--stack .fo-btn-primary.btn_one {
	width: 100%;
}

.fo-login-switch {
	font-size: 0.9rem;
	color: #5c6478;
	text-align: center;
}

.fo-login-switch a {
	font-weight: 600;
	color: #2c7aff;
	text-decoration: none;
}

.fo-login-switch a:hover {
	text-decoration: underline;
}

.fo-register-card .fo-field {
	margin-bottom: 1rem;
}

.fo-select.fo-input {
	appearance: auto;
	padding: 0.65rem 0.85rem;
	min-height: calc(0.65rem * 2 + 1.5rem + 2px);
}

.fo-hint {
	font-size: 0.8rem;
	color: #6b7280;
}

/* Candidate main: same pastel gradient as .section-top hero */
section.login_register.fo-candidate-content {
	background: linear-gradient(to left, rgb(228, 242, 254), rgb(255, 238, 254));
}

/* Candidate navbar: current link (Purdue main-menu) */
#navigation #main-menu ul li a.active {
	color: #2c7aff;
	font-weight: 600;
}

/* Candidate navbar: user identity pill */
.fo-user-pill {
	display: inline-flex;
	align-items: center;
	gap: 0.55rem;
	max-width: min(220px, 100%);
	padding: 0.35rem 0.65rem 0.35rem 0.35rem;
	border-radius: 999px;
	background: linear-gradient(135deg, #f8faff 0%, #eef3ff 100%);
	border: 1px solid rgba(44, 122, 255, 0.22);
	box-shadow: 0 4px 14px rgba(11, 16, 74, 0.06);
}

.fo-user-pill__avatar {
	flex-shrink: 0;
	width: 2.1rem;
	height: 2.1rem;
	border-radius: 50%;
	display: inline-flex;
	align-items: center;
	justify-content: center;
	font-family: "Lexend", system-ui, sans-serif;
	font-size: 0.72rem;
	font-weight: 700;
	letter-spacing: 0.04em;
	color: #fff;
	background: linear-gradient(145deg, #2c7aff 0%, #0b104a 100%);
	box-shadow: 0 2px 8px rgba(44, 122, 255, 0.35);
}

.fo-user-pill__meta {
	display: flex;
	flex-direction: column;
	align-items: flex-start;
	min-width: 0;
	line-height: 1.15;
}

.fo-user-pill__name {
	font-family: "Lexend", system-ui, sans-serif;
	font-size: 0.82rem;
	font-weight: 600;
	color: #0b104a;
	max-width: 100%;
	overflow: hidden;
	text-overflow: ellipsis;
	white-space: nowrap;
}

.fo-user-pill__role {
	font-size: 0.62rem;
	font-weight: 600;
	text-transform: uppercase;
	letter-spacing: 0.12em;
	color: #2c7aff;
	opacity: 0.95;
}

.fo-user-pill--mobile {
	max-width: 100%;
	width: 100%;
	box-sizing: border-box;
}

ul.mobile_menu li.fo-mobile-user-pill-wrap {
	pointer-events: none;
	padding: 0.65rem 0 0.85rem;
	margin-bottom: 0.35rem;
	border-bottom: 1px solid rgba(11, 16, 74, 0.08);
}

/* Candidate navbar: compact Déconnexion */
#navigation.site-navigation .call_to_action .btn_two.fo-candidate-logout {
	padding: 0.35rem 0.95rem;
	font-size: 0.78rem;
	font-weight: 600;
	border-width: 1px;
	line-height: 1.25;
}

.sm_menu_outer .mobile_menu li.fo-mobile-logout a.fo-candidate-logout,
#navigation.site-navigation ul.mobile_menu li.fo-mobile-logout a.fo-candidate-logout {
	padding-top: 10px;
	padding-bottom: 10px;
	font-size: 0.8rem;
	font-weight: 600;
}

/* Front candidate charte: same colors as mission detail design */
.fo-charte-ui .fo-charte-card {
	background: #fff;
	border-radius: 24px;
	border: 1px solid #f0f0f0;
	overflow: hidden;
	box-shadow: 0 10px 40px rgba(0, 0, 0, 0.1);
}

.fo-charte-ui .fo-charte-header {
	background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
	color: #fff;
	border-bottom: 0;
}

.fo-charte-ui .btn-primary {
	background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
	border: 0;
	color: #fff;
}

.fo-charte-ui .btn-primary:hover,
.fo-charte-ui .btn-primary:focus {
	color: #fff;
	box-shadow: 0 4px 15px rgba(102, 126, 234, 0.35);
}

.fo-charte-ui .btn-outline-primary {
	border-color: #667eea;
	color: #667eea;
}

.fo-charte-ui .btn-outline-primary:hover,
.fo-charte-ui .btn-outline-primary:focus {
	background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
	border-color: transparent;
	color: #fff;
}

.fo-charte-ui .btn-outline-secondary {
	background: #f0f0f0;
	border-color: #f0f0f0;
	color: #666;
}

.fo-charte-ui .btn-outline-secondary:hover,
.fo-charte-ui .btn-outline-secondary:focus {
	background: #667eea;
	border-color: #667eea;
	color: #fff;
}

.fo-charte-ui .badge-success {
	background: #10b981;
}

.fo-charte-ui .badge-danger {
	background: #dc2626;
}

.fo-charte-ui .badge-warning {
	background: #f59e0b;
	color: #1f2937;
}

.fo-charte-ui .badge-light {
	background: #f8f9fa;
	color: #555;
	border: 1px solid #f0f0f0;
}

.fo-charte-ui .progress {
	background: #f0f0f0;
	border-radius: 50px;
}

.fo-charte-ui .progress .progress-bar {
	background: #10b981 !important;
}

.fo-charte-ui .list-group-item {
	border-color: #f0f0f0;
}

.fo-charte-ui .list-group-item-action:hover,
.fo-charte-ui .list-group-item-action:focus {
	background: #f8f9fa;
	color: #333;
}

.fo-charte-ui .page-item.active .page-link {
	background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
	border-color: transparent;
}

.fo-charte-ui .page-link {
	color: #667eea;
	border-color: #f0f0f0;
}

.fo-charte-ui .page-link:hover,
.fo-charte-ui .page-link:focus {
	background: #f8f9fa;
	color: #764ba2;
}

.fo-charte-ui .btn-link {
	color: #333;
	text-decoration: none;
}

.fo-charte-ui .btn-link:hover,
.fo-charte-ui .btn-link:focus {
	color: #667eea;
	text-decoration: none;
}

/* FXML-like candidate catalog layout translated to Symfony/Twig */
.fo-fxml-catalog.fo-shell-root {
	overflow: hidden;
	padding: 4px;
}

.fo-fxml-catalog .fo-bg-orb {
	position: absolute;
	border-radius: 9999px;
	pointer-events: none;
	z-index: 0;
	filter: blur(0.5px);
}

.fo-fxml-catalog .fo-bg-orb-1 {
	width: 500px;
	height: 500px;
	left: -260px;
	top: -130px;
	background: rgba(94, 84, 142, 0.06);
}

.fo-fxml-catalog .fo-bg-orb-2 {
	width: 380px;
	height: 380px;
	right: -130px;
	top: 220px;
	background: rgba(159, 134, 192, 0.05);
}

.fo-fxml-catalog .fo-bg-orb-3 {
	width: 280px;
	height: 280px;
	right: 110px;
	top: -90px;
	background: rgba(224, 177, 203, 0.05);
}

.fo-fxml-catalog .fo-catalog-header,
.fo-fxml-catalog form,
.fo-fxml-catalog .row,
.fo-fxml-catalog nav {
	z-index: 1;
}

.fo-fxml-catalog .fo-catalog-header h3 {
	font-size: 32px;
	font-weight: 900;
	color: #231942;
	letter-spacing: -0.02em;
}

.fo-fxml-catalog .fo-catalog-header p {
	font-size: 16px;
	color: #6b7280;
}

.fo-fxml-catalog .fo-glass-card {
	background: rgba(255, 255, 255, 0.84);
	border: 1px solid rgba(216, 201, 240, 0.65);
	box-shadow: 0 14px 40px rgba(35, 25, 66, 0.09);
	backdrop-filter: blur(2px);
}

.fo-fxml-catalog .fo-filter-combo {
	background: #fff;
	border: 1px solid #d8c9f0;
	border-radius: 12px;
	min-height: 46px;
	box-shadow: none;
}

.fo-fxml-catalog .fo-langue-wrap {
	display: block;
}

.fo-fxml-catalog .fo-langue-combo {
	opacity: 1;
}

.fo-fxml-catalog .fo-search-wrap {
	display: flex;
	align-items: center;
	background: #fff;
	border: 1.5px solid #d8c9f0;
	border-radius: 50px;
	padding: 5px;
	box-shadow: 0 8px 24px rgba(94, 84, 142, 0.08);
}

.fo-fxml-catalog .fo-search-wrap .fo-search-input {
	background: transparent;
	border: 0;
	padding: 10px 20px;
	height: auto;
}

.fo-fxml-catalog .fo-search-wrap .fo-search-input:focus {
	box-shadow: none;
	border: 0;
}

.fo-fxml-catalog .fo-search-button {
	background: linear-gradient(135deg, #667eea 0%, #5e548e 100%);
	color: #fff;
	border: 0;
	border-radius: 999px;
	padding: 10px 20px;
	font-weight: 700;
}

.fo-fxml-catalog .fo-search-button:hover,
.fo-fxml-catalog .fo-search-button:focus {
	color: #fff;
	box-shadow: 0 8px 22px rgba(94, 84, 142, 0.28);
}

.fo-fxml-catalog .fo-reset-link {
	font-size: 0.85rem;
	font-weight: 600;
	color: #6b7280;
	text-decoration: none;
}

.fo-fxml-catalog .fo-reset-link:hover,
.fo-fxml-catalog .fo-reset-link:focus {
	color: #5e548e;
	text-decoration: none;
}

.fo-fxml-catalog .fo-stat-card {
	padding: 25px;
	min-height: 140px;
	min-width: 180px;
	display: flex;
	flex-direction: column;
	justify-content: center;
	gap: 8px;
	border-radius: 18px;
}

.fo-fxml-catalog .fo-stat-card small {
	font-size: 14px;
	font-weight: 600;
	color: #6b7280;
	text-transform: none;
}

.fo-fxml-catalog .fo-stat-card strong {
	font-size: 36px;
	line-height: 1;
	font-weight: 900;
	color: #231942;
}

.fo-fxml-catalog .fo-course-card {
	max-width: 350px;
	margin: 0 auto;
	border-radius: 20px;
	transition: transform 0.25s ease, box-shadow 0.25s ease;
	box-shadow: 0 10px 30px rgba(94, 84, 142, 0.15);
}

.fo-fxml-catalog .fo-course-card:hover {
	transform: translateY(-3px);
	box-shadow: 0 18px 40px rgba(94, 84, 142, 0.3);
}

.fo-fxml-catalog .fo-course-cover {
	height: 160px;
	background: #5e548e;
	overflow: hidden;
	border-top-left-radius: 20px;
	border-top-right-radius: 20px;
}

.fo-fxml-catalog .fo-course-cover img {
	width: 100%;
	height: 100%;
	object-fit: cover;
}

.fo-fxml-catalog .fo-card-badges .badge {
	padding: 0.4rem 0.7rem;
	font-size: 0.73rem;
	font-weight: 700;
	border-radius: 999px;
}

.fo-fxml-catalog .fo-level-badge--beginner {
	background: #d1fae5;
	color: #065f46;
}

.fo-fxml-catalog .fo-level-badge--intermediate {
	background: #fef3c7;
	color: #92400e;
}

.fo-fxml-catalog .fo-level-badge--advanced {
	background: #fee2e2;
	color: #991b1b;
}

.fo-fxml-catalog .fo-category-badge {
	background: #f8fafc;
	border: 1px solid #e2e8f0;
	color: #4b5563;
}

.fo-fxml-catalog .fo-course-title {
	font-weight: 800;
	color: #1f2937;
	font-size: 1.1rem;
}

.fo-fxml-catalog .fo-course-description {
	line-height: 1.45;
	min-height: 58px;
	max-height: 60px;
	overflow: hidden;
}

.fo-fxml-catalog .fo-courses-grid {
	justify-content: center;
}

.fo-fxml-catalog .fo-meta-row {
	display: flex;
	align-items: center;
	flex-wrap: wrap;
	gap: 12px 16px;
	color: #6b7280;
}

.fo-fxml-catalog .fo-meta-item {
	display: inline-flex;
	align-items: center;
	font-size: 0.86rem;
}

.fo-fxml-catalog .fo-price-label {
	color: #5e548e;
	font-weight: 800;
	font-size: 0.88rem;
}

.fo-fxml-catalog .btn-warning {
	background: #f59e0b;
	border-color: #f59e0b;
	color: #fff;
	font-weight: 700;
	border-radius: 999px;
	padding-top: 0.52rem;
	padding-bottom: 0.52rem;
}

.fo-fxml-catalog .btn-warning:hover,
.fo-fxml-catalog .btn-warning:focus {
	background: #d97706;
	border-color: #d97706;
	color: #fff;
}

.fo-fxml-catalog .fo-btn-commencer,
.fo-fxml-catalog .btn-primary.btn-block {
	border-radius: 999px;
	padding-top: 0.52rem;
	padding-bottom: 0.52rem;
	font-weight: 700;
}

@media (max-width: 991px) {
	.fo-fxml-catalog .fo-course-card {
		max-width: 100%;
	}
}

@media (max-width: 767px) {
	.fo-fxml-catalog .fo-search-wrap {
		flex-direction: column;
		align-items: stretch;
		border-radius: 16px;
		gap: 8px;
		padding: 10px;
	}

	.fo-fxml-catalog .fo-search-wrap .btn {
		margin-left: 0 !important;
		width: 100%;
	}

	.fo-fxml-catalog .fo-bg-orb {
		display: none;
	}
}

/* Player layout (cours_show + lecon_show): FXML-inspired, cleaner sidebar */
.fo-player-layout__left {
	max-width: 300px;
}

.fo-player-sidebar {
	top: 20px;
	overflow: hidden;
}

.fo-player-sidebar__header {
	padding: 0.8rem 1rem;
}

.fo-player-sidebar__header .font-weight-bold {
	font-size: 0.9rem;
}

.fo-player-sidebar__header .badge {
	font-size: 0.75rem;
}

.fo-player-sidebar__scroll {
	max-height: calc(100vh - 230px);
	overflow-y: auto;
	background: #fff;
}

.fo-player-module {
	padding: 0.8rem 0.85rem;
	border-bottom: 1px solid #f0f0f0;
}

.fo-player-module__index {
	font-size: 0.8rem;
	font-weight: 700;
	color: #231942;
	line-height: 1.2;
}

.fo-player-module__title {
	font-size: 0.75rem;
	line-height: 1.2;
	color: #6b7280;
	white-space: normal;
	word-break: break-word;
}

.fo-player-module__count {
	font-size: 0.68rem;
}

.fo-player-lesson-link {
	text-decoration: none;
	font-size: 0.76rem;
	padding: 0.35rem 0.45rem;
	border-radius: 8px;
	margin-bottom: 3px;
	background: #f8fafc;
}

.fo-player-lesson-link.is-active {
	background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
}

.fo-player-lesson-link__title {
	white-space: normal;
	word-break: break-word;
	line-height: 1.2;
	padding-right: 0.35rem;
}

.fo-player-lesson-link__check {
	font-size: 0.68rem;
	flex-shrink: 0;
}

.fo-player-module__quiz-btn {
	font-size: 0.74rem;
	padding: 0.3rem 0.4rem;
	border-radius: 8px;
}

/* Anti-copy helper for quiz/test question blocks */
.fo-anti-copy,
.fo-anti-copy * {
	-webkit-user-select: none;
	-moz-user-select: none;
	-ms-user-select: none;
	user-select: none;
	-webkit-touch-callout: none;
}

.fo-anti-copy-page,
.fo-anti-copy-page * {
	-webkit-user-select: none;
	-moz-user-select: none;
	-ms-user-select: none;
	user-select: none;
	-webkit-touch-callout: none;
	-webkit-tap-highlight-color: transparent;
}

.fo-anti-copy .form-check-input,
.fo-anti-copy button,
.fo-anti-copy a,
.fo-anti-copy input,
.fo-anti-copy label {
	-webkit-user-select: none;
	-moz-user-select: none;
	-ms-user-select: none;
	user-select: none;
}

@media (max-width: 991px) {
	.fo-player-layout__left {
		max-width: 100%;
	}

	.fo-player-sidebar {
		position: static !important;
	}

	.fo-player-sidebar__scroll {
		max-height: none;
	}
}

/* Front office: compact navbar + logo size */
#navigation.site-navigation {
	padding: 10px 0;
}

#navigation .container .row {
	align-items: center;
}

/* Logo + company name */
.site-brand {
	gap: 0.65rem;
	min-width: 0;
}

.site-brand__name {
	font-family: "Lexend", system-ui, sans-serif;
	font-weight: 700;
	font-size: 1.35rem;
	line-height: 1.2;
	color: #0b104a;
	text-decoration: none;
	letter-spacing: -0.02em;
	white-space: nowrap;
}

.site-brand:hover .site-brand__name,
.site-brand:focus .site-brand__name,
.site-brand:focus-visible .site-brand__name {
	color: #2c7aff;
}

.site-brand:focus-visible {
	outline: 2px solid #2c7aff;
	outline-offset: 3px;
	border-radius: 4px;
}

.site-logo {
	display: inline-block;
	width: auto;
	max-width: 200px;
	line-height: 0;
	flex-shrink: 0;
	vertical-align: middle;
}

.site-logo img,
img.fo-brand-logo {
	display: block;
	max-height: 44px;
	width: auto;
	max-width: 100%;
	height: auto;
	object-fit: contain;
}

@media only screen and (max-width: 575px) {
	#navigation.site-navigation {
		padding: 12px 12px;
	}

	.site-logo img,
	img.fo-brand-logo {
		max-height: 38px;
	}

	.site-brand__name {
		font-size: 1.15rem;
	}
}

/* Navbar: back to home */
.fo-nav-back {
	display: inline-flex;
	align-items: center;
	justify-content: center;
	width: 2.25rem;
	height: 2.25rem;
	flex-shrink: 0;
	border-radius: 10px;
	color: #0b104a;
	background: #f0f4ff;
	border: 1px solid #dbe4ff;
	text-decoration: none;
	transition: background 0.2s, color 0.2s, border-color 0.2s;
}

.fo-nav-back:hover,
.fo-nav-back:focus {
	color: #2c7aff;
	background: #e8efff;
	border-color: #c7d7ff;
	text-decoration: none;
}

.fo-nav-back i {
	font-size: 1rem;
}

/* Login / register: clearer form */
.fo-login-section {
	background: linear-gradient(180deg, #f5f7fb 0%, #eef2f8 100%);
}

.fo-login-card {
	background: #fff;
	border-radius: 16px;
	padding: 2rem 1.75rem;
	box-shadow: 0 12px 40px rgba(15, 23, 42, 0.08);
	border: 1px solid rgba(15, 23, 42, 0.06);
}

.fo-login-card__title {
	font-family: "Lexend", system-ui, sans-serif;
	font-size: 1.5rem;
	font-weight: 700;
	color: #0b104a;
	margin: 0 0 0.5rem;
	line-height: 1.3;
}

.fo-login-card__lead {
	color: #5c6478;
	font-size: 0.95rem;
	margin: 0 0 1.5rem;
	line-height: 1.5;
}

.fo-login-alert {
	font-size: 0.9rem;
	border-radius: 10px;
}

.fo-field {
	margin-bottom: 1.15rem;
}

.fo-label {
	display: block;
	font-weight: 600;
	font-size: 0.875rem;
	color: #0b104a;
	margin-bottom: 0.4rem;
}

.fo-input.form-control {
	border-radius: 10px;
	border: 1px solid #d8dee8;
	padding: 0.65rem 0.85rem;
	font-size: 0.95rem;
	transition: border-color 0.2s, box-shadow 0.2s;
}

.fo-input.form-control:focus {
	border-color: #2c7aff;
	box-shadow: 0 0 0 3px rgba(44, 122, 255, 0.2);
	outline: none;
}

.fo-login-form .fo-login-actions {
	display: flex;
	flex-direction: column;
	gap: 0.75rem;
	margin-top: 0.25rem;
}

@media (min-width: 400px) {
	.fo-login-form .fo-login-actions:not(.fo-login-actions--stack) {
		flex-direction: row;
		align-items: stretch;
		gap: 0.75rem;
	}

	.fo-btn-primary {
		flex: 1 1 auto;
	}

	.fo-btn-secondary {
		flex: 0 0 auto;
		min-width: 7rem;
		justify-content: center;
		display: inline-flex;
		align-items: center;
	}
}

.fo-btn-primary.btn_one {
	width: 100%;
	border-radius: 10px;
	padding: 0.7rem 1rem;
	font-weight: 600;
}

.fo-btn-secondary.btn_two {
	border-radius: 10px;
	padding: 0.65rem 1.1rem;
	font-weight: 600;
	text-align: center;
}

.fo-login-actions--stack .fo-btn-primary.btn_one {
	width: 100%;
}

.fo-login-switch {
	font-size: 0.9rem;
	color: #5c6478;
	text-align: center;
}

.fo-login-switch a {
	font-weight: 600;
	color: #2c7aff;
	text-decoration: none;
}

.fo-login-switch a:hover {
	text-decoration: underline;
}

.fo-register-card .fo-field {
	margin-bottom: 1rem;
}

.fo-select.fo-input {
	appearance: auto;
	padding: 0.65rem 0.85rem;
	min-height: calc(0.65rem * 2 + 1.5rem + 2px);
}

.fo-hint {
	font-size: 0.8rem;
	color: #6b7280;
}

/* Candidate main: same pastel gradient as .section-top hero */
section.login_register.fo-candidate-content {
	background: linear-gradient(to left, rgb(228, 242, 254), rgb(255, 238, 254));
}

/* Candidate navbar: current link (Purdue main-menu) */
#navigation #main-menu ul li a.active {
	color: #2c7aff;
	font-weight: 600;
}

/* Candidate navbar: user identity pill */
.fo-user-pill {
	display: inline-flex;
	align-items: center;
	gap: 0.55rem;
	max-width: min(220px, 100%);
	padding: 0.35rem 0.65rem 0.35rem 0.35rem;
	border-radius: 999px;
	background: linear-gradient(135deg, #f8faff 0%, #eef3ff 100%);
	border: 1px solid rgba(44, 122, 255, 0.22);
	box-shadow: 0 4px 14px rgba(11, 16, 74, 0.06);
}

.fo-user-pill__avatar {
	flex-shrink: 0;
	width: 2.1rem;
	height: 2.1rem;
	border-radius: 50%;
	display: inline-flex;
	align-items: center;
	justify-content: center;
	font-family: "Lexend", system-ui, sans-serif;
	font-size: 0.72rem;
	font-weight: 700;
	letter-spacing: 0.04em;
	color: #fff;
	background: linear-gradient(145deg, #2c7aff 0%, #0b104a 100%);
	box-shadow: 0 2px 8px rgba(44, 122, 255, 0.35);
}

.fo-user-pill__meta {
	display: flex;
	flex-direction: column;
	align-items: flex-start;
	min-width: 0;
	line-height: 1.15;
}

.fo-user-pill__name {
	font-family: "Lexend", system-ui, sans-serif;
	font-size: 0.82rem;
	font-weight: 600;
	color: #0b104a;
	max-width: 100%;
	overflow: hidden;
	text-overflow: ellipsis;
	white-space: nowrap;
}

.fo-user-pill__role {
	font-size: 0.62rem;
	font-weight: 600;
	text-transform: uppercase;
	letter-spacing: 0.12em;
	color: #2c7aff;
	opacity: 0.95;
}

.fo-user-pill--mobile {
	max-width: 100%;
	width: 100%;
	box-sizing: border-box;
}

ul.mobile_menu li.fo-mobile-user-pill-wrap {
	pointer-events: none;
	padding: 0.65rem 0 0.85rem;
	margin-bottom: 0.35rem;
	border-bottom: 1px solid rgba(11, 16, 74, 0.08);
}

/* Candidate navbar: compact Déconnexion */
#navigation.site-navigation .call_to_action .btn_two.fo-candidate-logout {
	padding: 0.35rem 0.95rem;
	font-size: 0.78rem;
	font-weight: 600;
	border-width: 1px;
	line-height: 1.25;
}

.sm_menu_outer .mobile_menu li.fo-mobile-logout a.fo-candidate-logout,
#navigation.site-navigation ul.mobile_menu li.fo-mobile-logout a.fo-candidate-logout {
	padding-top: 10px;
	padding-bottom: 10px;
	font-size: 0.8rem;
	font-weight: 600;
}

/* Front candidate charte: same colors as mission detail design */
.fo-charte-ui .fo-charte-card {
	background: #fff;
	border-radius: 24px;
	border: 1px solid #f0f0f0;
	overflow: hidden;
	box-shadow: 0 10px 40px rgba(0, 0, 0, 0.1);
}

.fo-charte-ui .fo-charte-header {
	background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
	color: #fff;
	border-bottom: 0;
}

.fo-charte-ui .btn-primary {
	background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
	border: 0;
	color: #fff;
}

.fo-charte-ui .btn-primary:hover,
.fo-charte-ui .btn-primary:focus {
	color: #fff;
	box-shadow: 0 4px 15px rgba(102, 126, 234, 0.35);
}

.fo-charte-ui .btn-outline-primary {
	border-color: #667eea;
	color: #667eea;
}

.fo-charte-ui .btn-outline-primary:hover,
.fo-charte-ui .btn-outline-primary:focus {
	background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
	border-color: transparent;
	color: #fff;
}

.fo-charte-ui .btn-outline-secondary {
	background: #f0f0f0;
	border-color: #f0f0f0;
	color: #666;
}

.fo-charte-ui .btn-outline-secondary:hover,
.fo-charte-ui .btn-outline-secondary:focus {
	background: #667eea;
	border-color: #667eea;
	color: #fff;
}

.fo-charte-ui .badge-success {
	background: #10b981;
}

.fo-charte-ui .badge-danger {
	background: #dc2626;
}

.fo-charte-ui .badge-warning {
	background: #f59e0b;
	color: #1f2937;
}

.fo-charte-ui .badge-light {
	background: #f8f9fa;
	color: #555;
	border: 1px solid #f0f0f0;
}

.fo-charte-ui .progress {
	background: #f0f0f0;
	border-radius: 50px;
}

.fo-charte-ui .progress .progress-bar {
	background: #10b981 !important;
}

.fo-charte-ui .list-group-item {
	border-color: #f0f0f0;
}

.fo-charte-ui .list-group-item-action:hover,
.fo-charte-ui .list-group-item-action:focus {
	background: #f8f9fa;
	color: #333;
}

.fo-charte-ui .page-item.active .page-link {
	background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
	border-color: transparent;
}

.fo-charte-ui .page-link {
	color: #667eea;
	border-color: #f0f0f0;
}

.fo-charte-ui .page-link:hover,
.fo-charte-ui .page-link:focus {
	background: #f8f9fa;
	color: #764ba2;
}

.fo-charte-ui .btn-link {
	color: #333;
	text-decoration: none;
}

.fo-charte-ui .btn-link:hover,
.fo-charte-ui .btn-link:focus {
	color: #667eea;
	text-decoration: none;
}

/* FXML-like candidate catalog layout translated to Symfony/Twig */
.fo-fxml-catalog.fo-shell-root {
	overflow: hidden;
	padding: 4px;
}

.fo-fxml-catalog .fo-bg-orb {
	position: absolute;
	border-radius: 9999px;
	pointer-events: none;
	z-index: 0;
	filter: blur(0.5px);
}

.fo-fxml-catalog .fo-bg-orb-1 {
	width: 500px;
	height: 500px;
	left: -260px;
	top: -130px;
	background: rgba(94, 84, 142, 0.06);
}

.fo-fxml-catalog .fo-bg-orb-2 {
	width: 380px;
	height: 380px;
	right: -130px;
	top: 220px;
	background: rgba(159, 134, 192, 0.05);
}

.fo-fxml-catalog .fo-bg-orb-3 {
	width: 280px;
	height: 280px;
	right: 110px;
	top: -90px;
	background: rgba(224, 177, 203, 0.05);
}

.fo-fxml-catalog .fo-catalog-header,
.fo-fxml-catalog form,
.fo-fxml-catalog .row,
.fo-fxml-catalog nav {
	z-index: 1;
}

.fo-fxml-catalog .fo-catalog-header h3 {
	font-size: 32px;
	font-weight: 900;
	color: #231942;
	letter-spacing: -0.02em;
}

.fo-fxml-catalog .fo-catalog-header p {
	font-size: 16px;
	color: #6b7280;
}

.fo-fxml-catalog .fo-glass-card {
	background: rgba(255, 255, 255, 0.84);
	border: 1px solid rgba(216, 201, 240, 0.65);
	box-shadow: 0 14px 40px rgba(35, 25, 66, 0.09);
	backdrop-filter: blur(2px);
}

.fo-fxml-catalog .fo-filter-combo {
	background: #fff;
	border: 1px solid #d8c9f0;
	border-radius: 12px;
	min-height: 46px;
	box-shadow: none;
}

.fo-fxml-catalog .fo-langue-wrap {
	display: block;
}

.fo-fxml-catalog .fo-langue-combo {
	opacity: 1;
}

.fo-fxml-catalog .fo-search-wrap {
	display: flex;
	align-items: center;
	background: #fff;
	border: 1.5px solid #d8c9f0;
	border-radius: 50px;
	padding: 5px;
	box-shadow: 0 8px 24px rgba(94, 84, 142, 0.08);
}

.fo-fxml-catalog .fo-search-wrap .fo-search-input {
	background: transparent;
	border: 0;
	padding: 10px 20px;
	height: auto;
}

.fo-fxml-catalog .fo-search-wrap .fo-search-input:focus {
	box-shadow: none;
	border: 0;
}

.fo-fxml-catalog .fo-search-button {
	background: linear-gradient(135deg, #667eea 0%, #5e548e 100%);
	color: #fff;
	border: 0;
	border-radius: 999px;
	padding: 10px 20px;
	font-weight: 700;
}

.fo-fxml-catalog .fo-search-button:hover,
.fo-fxml-catalog .fo-search-button:focus {
	color: #fff;
	box-shadow: 0 8px 22px rgba(94, 84, 142, 0.28);
}

.fo-fxml-catalog .fo-reset-link {
	font-size: 0.85rem;
	font-weight: 600;
	color: #6b7280;
	text-decoration: none;
}

.fo-fxml-catalog .fo-reset-link:hover,
.fo-fxml-catalog .fo-reset-link:focus {
	color: #5e548e;
	text-decoration: none;
}

.fo-fxml-catalog .fo-btn-state,
.fo-fxml-catalog .fo-btn-state-active {
	border-radius: 999px;
	padding: 0.45rem 0.95rem;
	font-size: 0.8rem;
	font-weight: 700;
	border: 0;
}

.fo-fxml-catalog .fo-btn-state {
	background: #f3e8ff;
	color: #5e548e;
}

.fo-fxml-catalog .fo-btn-state:hover,
.fo-fxml-catalog .fo-btn-state:focus {
	color: #fff;
	background: #6d5ca8;
}

.fo-fxml-catalog .fo-btn-state-active {
	background: #5e548e;
	color: #fff;
}

.fo-fxml-catalog .fo-my-progress-wrap .fo-my-progress-bar {
	height: 8px;
	border-radius: 999px;
	overflow: hidden;
	background: #eee7fb;
}

.fo-fxml-catalog .fo-my-progress-wrap .progress-bar {
	background: linear-gradient(135deg, #667eea 0%, #5e548e 100%) !important;
}

.fo-fxml-catalog .fo-stat-card {
	padding: 25px;
	min-height: 140px;
	min-width: 180px;
	display: flex;
	flex-direction: column;
	justify-content: center;
	gap: 8px;
	border-radius: 18px;
}

.fo-fxml-catalog .fo-stat-card small {
	font-size: 14px;
	font-weight: 600;
	color: #6b7280;
	text-transform: none;
}

.fo-fxml-catalog .fo-stat-card strong {
	font-size: 36px;
	line-height: 1;
	font-weight: 900;
	color: #231942;
}

.fo-fxml-catalog .fo-course-card {
	max-width: 350px;
	margin: 0 auto;
	border-radius: 20px;
	transition: transform 0.25s ease, box-shadow 0.25s ease;
	box-shadow: 0 10px 30px rgba(94, 84, 142, 0.15);
}

.fo-fxml-catalog .fo-course-card:hover {
	transform: translateY(-3px);
	box-shadow: 0 18px 40px rgba(94, 84, 142, 0.3);
}

.fo-fxml-catalog .fo-course-cover {
	height: 160px;
	background: #5e548e;
	overflow: hidden;
	border-top-left-radius: 20px;
	border-top-right-radius: 20px;
}

.fo-fxml-catalog .fo-course-cover img {
	width: 100%;
	height: 100%;
	object-fit: cover;
}

.fo-fxml-catalog .fo-card-badges .badge {
	padding: 0.4rem 0.7rem;
	font-size: 0.73rem;
	font-weight: 700;
	border-radius: 999px;
}

.fo-fxml-catalog .fo-level-badge--beginner {
	background: #d1fae5;
	color: #065f46;
}

.fo-fxml-catalog .fo-level-badge--intermediate {
	background: #fef3c7;
	color: #92400e;
}

.fo-fxml-catalog .fo-level-badge--advanced {
	background: #fee2e2;
	color: #991b1b;
}

.fo-fxml-catalog .fo-category-badge {
	background: #f8fafc;
	border: 1px solid #e2e8f0;
	color: #4b5563;
}

.fo-fxml-catalog .fo-course-title {
	font-weight: 800;
	color: #1f2937;
	font-size: 1.1rem;
}

.fo-fxml-catalog .fo-course-description {
	line-height: 1.45;
	min-height: 58px;
	max-height: 60px;
	overflow: hidden;
}

.fo-fxml-catalog .fo-courses-grid {
	justify-content: center;
}

.fo-fxml-catalog .fo-meta-row {
	display: flex;
	align-items: center;
	flex-wrap: wrap;
	gap: 12px 16px;
	color: #6b7280;
}

.fo-fxml-catalog .fo-meta-item {
	display: inline-flex;
	align-items: center;
	font-size: 0.86rem;
}

.fo-fxml-catalog .fo-price-label {
	color: #5e548e;
	font-weight: 800;
	font-size: 0.88rem;
}

.fo-fxml-catalog .btn-warning {
	background: #f59e0b;
	border-color: #f59e0b;
	color: #fff;
	font-weight: 700;
	border-radius: 999px;
	padding-top: 0.52rem;
	padding-bottom: 0.52rem;
}

.fo-fxml-catalog .btn-warning:hover,
.fo-fxml-catalog .btn-warning:focus {
	background: #d97706;
	border-color: #d97706;
	color: #fff;
}

.fo-fxml-catalog .fo-btn-commencer,
.fo-fxml-catalog .btn-primary.btn-block {
	border-radius: 999px;
	padding-top: 0.52rem;
	padding-bottom: 0.52rem;
	font-weight: 700;
}

@media (max-width: 991px) {
	.fo-fxml-catalog .fo-course-card {
		max-width: 100%;
	}
}

@media (max-width: 767px) {
	.fo-fxml-catalog .fo-search-wrap {
		flex-direction: column;
		align-items: stretch;
		border-radius: 16px;
		gap: 8px;
		padding: 10px;
	}

	.fo-fxml-catalog .fo-search-wrap .btn {
		margin-left: 0 !important;
		width: 100%;
	}

	.fo-fxml-catalog .fo-bg-orb {
		display: none;
	}
}

/* Player layout (cours_show + lecon_show): FXML-inspired, cleaner sidebar */
.fo-player-layout__left {
	max-width: 300px;
}

.fo-player-sidebar {
	top: 20px;
	overflow: hidden;
}

.fo-player-sidebar__header {
	padding: 0.8rem 1rem;
}

.fo-player-sidebar__header .font-weight-bold {
	font-size: 0.9rem;
}

.fo-player-sidebar__header .badge {
	font-size: 0.75rem;
}

.fo-player-sidebar__scroll {
	max-height: calc(100vh - 230px);
	overflow-y: auto;
	background: #fff;
}

.fo-player-module {
	padding: 0.8rem 0.85rem;
	border-bottom: 1px solid #f0f0f0;
}

.fo-player-module__index {
	font-size: 0.8rem;
	font-weight: 700;
	color: #231942;
	line-height: 1.2;
}

.fo-player-module__title {
	font-size: 0.75rem;
	line-height: 1.2;
	color: #6b7280;
	white-space: normal;
	word-break: break-word;
}

.fo-player-module__count {
	font-size: 0.68rem;
}

.fo-player-lesson-link {
	text-decoration: none;
	font-size: 0.76rem;
	padding: 0.35rem 0.45rem;
	border-radius: 8px;
	margin-bottom: 3px;
	background: #f8fafc;
}

.fo-player-lesson-link.is-active {
	background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
}

.fo-player-lesson-link__title {
	white-space: normal;
	word-break: break-word;
	line-height: 1.2;
	padding-right: 0.35rem;
}

.fo-player-lesson-link__check {
	font-size: 0.68rem;
	flex-shrink: 0;
}

.fo-player-module__quiz-btn {
	font-size: 0.74rem;
	padding: 0.3rem 0.4rem;
	border-radius: 8px;
}

/* Anti-copy helper for quiz/test question blocks */
.fo-anti-copy,
.fo-anti-copy * {
	-webkit-user-select: none;
	-moz-user-select: none;
	-ms-user-select: none;
	user-select: none;
	-webkit-touch-callout: none;
}

.fo-anti-copy-page,
.fo-anti-copy-page * {
	-webkit-user-select: none;
	-moz-user-select: none;
	-ms-user-select: none;
	user-select: none;
	-webkit-touch-callout: none;
	-webkit-tap-highlight-color: transparent;
}

.fo-anti-copy .form-check-input,
.fo-anti-copy button,
.fo-anti-copy a,
.fo-anti-copy input,
.fo-anti-copy label {
	-webkit-user-select: none;
	-moz-user-select: none;
	-ms-user-select: none;
	user-select: none;
}

@media (max-width: 991px) {
	.fo-player-layout__left {
		max-width: 100%;
	}

	.fo-player-sidebar {
		position: static !important;
	}

	.fo-player-sidebar__scroll {
		max-height: none;
	}
}

{% extends 'FrontOffice/main/base_candidate.html.twig' %}

{% block title %}Cours{% endblock %}

{% block stylesheets %}
    {{ parent() }}
    <link rel="stylesheet" href="{{ asset('FrontOffice/css/front-overrides.css') }}?v=20260405-1">
{% endblock %}

{% block candidate_page_heading %}Cours{% endblock %}

{% block candidate_breadcrumb %} / Cours{% endblock %}

{% block candidate_content_container_class %}container-fluid px-3 px-md-4 px-lg-5{% endblock %}

{% block candidate_content_row_class %}row{% endblock %}

{% block candidate_content_col_class %}col-12{% endblock %}

{% block candidate_content %}
    <div class="w-100 text-start fo-charte-ui fo-fxml-catalog fo-shell-root position-relative">

        <div class="fo-catalog-header mb-4 position-relative">
            <h3 class="mb-1">Catalogue de cours</h3>
            <p class="mb-0">{{ pagination.total|default(cours_list|length) }} cours disponibles</p>
        </div>

        <form method="get" class="mb-4 position-relative">
            <div class="fo-charte-card fo-glass-card p-3 p-md-4 mb-3">
                <div class="row align-items-end">
                    <div class="col-md-6 mb-3 mb-md-0">
                        <label for="course-level" class="d-block mb-2 font-weight-bold">Niveau</label>
                        <select id="course-level" name="niveau" class="form-control fo-filter-combo">
                            <option value="">Tous les niveaux</option>
                            {% for n in niveaux %}
                                <option value="{{ n }}" {{ filters.niveau == n ? 'selected' : '' }}>{{ n }}</option>
                            {% endfor %}
                        </select>
                    </div>
                    <div class="col-md-6 mb-3 mb-md-0">
                        <div class="fo-langue-wrap">
                            <label for="course-language" class="d-block mb-2 font-weight-bold">Langue</label>
                            <select id="course-language" class="form-control fo-filter-combo fo-langue-combo" disabled>
                                <option>Choisir une langue</option>
                            </select>
                        </div>
                    </div>
                </div>
            </div>
            <div class="fo-search-wrap mb-4">
                <label for="course-search" class="sr-only">Rechercher un cours</label>
                <input id="course-search" type="text" name="q" class="form-control fo-search-input" placeholder="Rechercher un cours par titre ou description..." value="{{ filters.q }}">
                <div class="d-flex mt-2">
                    <button type="submit" class="btn fo-search-button">Rechercher</button>
                    <select name="order" class="form-control ml-2" style="width: auto;" onchange="this.form.submit()">
                        <option value="recent" {{ filters.order == 'recent' ? 'selected' : '' }}>Plus récent</option>
                        <option value="price_asc" {{ filters.order == 'price_asc' ? 'selected' : '' }}>Prix croissant (€)</option>
                        <option value="price_desc" {{ filters.order == 'price_desc' ? 'selected' : '' }}>Prix décroissant (€)</option>
                    </select>
                </div>
            </div>
            <div class="text-right mb-1">
                <a href="{{ path('app_candidate_cours') }}" class="fo-reset-link">Reset</a>            </div>
        </form>

        {% set en_cours = 0 %}
        {% set completes = 0 %}
        {% for c in cours_list %}
            {% set p = course_states[c.id].progress|default(0) %}
            {% if p >= 100 %}
                {% set completes = completes + 1 %}
            {% elseif p > 0 %}
                {% set en_cours = en_cours + 1 %}
            {% endif %}
        {% endfor %}

        <div class="row text-center mb-4 position-relative">
            <div class="col-md-4 mb-3 mb-md-0"><div class="fo-charte-card fo-stat-card"><small>Cours disponibles</small><strong>{{ pagination.total|default(cours_list|length) }}</strong></div></div>
            <div class="col-md-4 mb-3 mb-md-0"><div class="fo-charte-card fo-stat-card"><small>En cours</small><strong>{{ en_cours }}</strong></div></div>
            <div class="col-md-4"><div class="fo-charte-card fo-stat-card"><small>Complétés</small><strong>{{ completes }}</strong></div></div>
        </div>

        {% if cours_list is empty %}
            <div class="alert alert-light border mb-0">Aucun cours n'est disponible pour le moment.</div>
        {% else %}
            <div class="row position-relative fo-courses-grid">
                {% for c in cours_list %}
                    {% set state = course_states[c.id]|default({}) %}
                    {% set level_class = c.niveau in ['Debutant', 'Débutant'] ? 'fo-level-badge--beginner' : (c.niveau in ['Intermediaire', 'Intermédiaire'] ? 'fo-level-badge--intermediate' : 'fo-level-badge--advanced') %}
                    {% set category = c.competencesVisees ? (c.competencesVisees|split(',')|first|trim) : 'Général' %}
                    <div class="col-xl-4 col-md-6 mb-4">
                        <div class="card h-100 fo-charte-card fo-course-card">
                            <div class="fo-course-cover">
                                {% if c.imageCouverture %}
                                    <img src="{{ path('app_candidate_cours_image', {id: c.id}) }}" class="card-img-top" alt="{{ c.titre|default('Cours') }}">
                                {% endif %}
                            </div>
                            <div class="card-body d-flex flex-column">
                                <div class="mb-2 d-flex align-items-center flex-wrap fo-card-badges">
                                    <span class="badge fo-level-badge {{ level_class }} mr-2">{{ c.niveau|default('Niveau') }}</span>
                                    <span class="badge fo-category-badge">{{ category }}</span>
                                </div>
                                <h5 class="card-title mb-2 fo-course-title">{{ c.titre|default('Cours') }}</h5>
                                <p class="card-text text-muted mb-3 fo-course-description">{{ c.description|default('Aucune description')|slice(0, 120) }}{% if c.description and c.description|length > 120 %}...{% endif %}</p>
                                <div class="fo-meta-row mb-3">
                                    <div class="fo-meta-item"><span class="mr-1">⏱</span><small>{{ c.duree|default('0') }} heures</small></div>
                                    {% if c.estPayant and c.prix and c.prix > 0 %}
                                        <div class="fo-meta-item"><span class="mr-1"></span><strong class="fo-price-label">{{ c.prix|number_format(2, '.', ' ') }} TND</strong></div>
                                    {% endif %}
                                    {% if c.estObligatoire %}
                                        <div class="fo-meta-item"><span class="mr-1"></span><small>Obligatoire</small></div>
                                    {% endif %}
                                </div>
                                <div class="mt-auto">
                                    {% if c.estPayant and c.prix and c.prix > 0 %}
                                        <a href="{{ path('app_candidate_cours_show', {id: c.id}) }}" class="btn btn-warning btn-sm btn-block fo-action-buy">Acheter {{ c.prix|number_format(2, '.', ' ') }} TND</a>
                                    {% elseif state.continue_lesson is defined and state.continue_lesson %}
                                        <a href="{{ path('app_candidate_lecon_show', {cours: c.id, id: state.continue_lesson.id}) }}" class="btn btn-primary btn-sm btn-block fo-btn-commencer">Accéder au cours</a>
                                    {% else %}
                                        <a href="{{ path('app_candidate_cours_show', {id: c.id}) }}" class="btn btn-primary btn-sm btn-block fo-btn-commencer">Commencer</a>
                                    {% endif %}
                                </div>
                            </div>
                        </div>
                    </div>
                {% endfor %}
            </div>

            {% if pagination.total_pages > 1 %}
                <nav aria-label="Pagination des cours" class="mt-2">
                    <ul class="pagination justify-content-center mb-0">
                        <li class="page-item {{ pagination.page <= 1 ? 'disabled' : '' }}">
                            <a class="page-link" href="{{ path('app_candidate_cours', {page: pagination.page - 1, q: filters.q, niveau: filters.niveau, order: filters.order}) }}">Precedent</a>
                        </li>
                        {% for p in 1..pagination.total_pages %}
                            <li class="page-item {{ p == pagination.page ? 'active' : '' }}">
                                <a class="page-link" href="{{ path('app_candidate_cours', {page: p, q: filters.q, niveau: filters.niveau, order: filters.order}) }}">{{ p }}</a>
                            </li>
                        {% endfor %}
                        <li class="page-item {{ pagination.page >= pagination.total_pages ? 'disabled' : '' }}">
                            <a class="page-link" href="{{ path('app_candidate_cours', {page: pagination.page + 1, q: filters.q, niveau: filters.niveau, order: filters.order}) }}">Suivant</a>
                        </li>
                    </ul>
                </nav>
            {% endif %}
        {% endif %}
    </div>
{% endblock %}

{% extends 'FrontOffice/main/base_candidate.html.twig' %}

{% block title %}Cours{% endblock %}

{% block stylesheets %}
